from typing import List

def split_array(nums: List[int], k: int) -> int:
    def can_split(max_sum: int) -> bool:
        """Can we split nums into at most k subarrays each with sum <= max_sum?"""
        count = 1
        current = 0
        for num in nums:
            if current + num > max_sum:
                count += 1
                current = num
                if count > k:
                    return False
            else:
                current += num
        return True

    lo, hi = max(nums), sum(nums)
    while lo < hi:
        mid = lo + (hi - lo) // 2
        if can_split(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo

